sort=[];
push=(title,url,type1,type2)=>sort.push({
		title: title,
		url: url,
		style: {
				layout_flexGrow: type1,
				layout_flexBasisPercent: type2
			}
	});
push("全部🔖小说",``,1,1)	
D=org.jsoup.Jsoup.parse(java.ajax("{{getUrl()}}modules/article/articlefilter.php"))
D.select("#sch-sel li").forEach(n=>{
	li=n.select("label")
	push(li.text(),li.attr("href"),1,1)
	n.select("li a").forEach(t=>{
	let url=String(t.attr("href")).replace(/\d{1}\.html/,'{{page}}.html')
	push(t.text(),url,1,0.25)	
	})
	})
//java.log(JSON.stringify(sort))
JSON.stringify(sort)

