function Ajax(url) {
    const { java, cookie } = this;
    let src = java.ajax(url);
    if (/Just a moment/.test(src)) {
        cookie.removeCookie(url);
        src = java.startBrowserAwait(url, "验证", false).body();
    }
    return src;
}

