#chapterlist a
@js:
var chapterList = [];
var volumes = new Set();

result.toArray().forEach(list => {
    let title = String(list.text());
    let url = list.attr('href');
    let volumeTitle = title.split(/\s+/)[0];

    let isVolumePattern = /^(第[一二三四五六七八九十百]+卷|第\d+(?:\.\d+)?卷)$/.test(volumeTitle);

    if (isVolumePattern && !volumes.has(volumeTitle)) {
        volumes.add(volumeTitle);
        chapterList.push({
            title: volumeTitle,
            url: null,
            isVolume: true
        });
    }

    chapterList.push({
        title: isVolumePattern ? title.replace(new RegExp(`${volumeTitle}\\s+`), "") : title,
        url,
        isVolume: false
    });
});

chapterList;

