function login() {
    var user = source.getLoginInfoMap();
    var loginParams = "name=" + encodeURIComponent(user.get("账号")) + "&pass=" + encodeURIComponent(user.get("密码"));
    var headers = {"Content-Type": "application/x-www-form-urlencoded", "token": ""};

    var req = java.post(baseUrl + "user/login/save", loginParams, headers);
    var body = JSON.parse(req.body());

    if (body.result === "success") {
          var cs = Array.from(req.cookies(), function(pair) { return pair[0] + "=" + pair[1]; }).join(";");
        source.setVariable(cs);
        return source.putLoginHeader(JSON.stringify({Cookie: cs}));
    } else {
        java.log("登录失败，响应内容: " + response.body());
        throw Error("登录失败");
    }
}

function signIn() {
  var log = (msg) => {
  	if(msg==null) return;
    java.longToast(msg);
    return java.log(msg);
  };
  var qd = java.ajax(baseUrl + '/?d=user&c=ajax&m=qd');
  var data = JSON.parse(qd), 
  zt = data.zt, str = data.str;
  //log(qd)
  if(zt=="ok"){
    return log("签到成功！");
  }else if(zt=="yes"){
    return log("今日已签到");
  }else if(zt=="no"){
    log("签到失败！\n未登录或" + str);
  }
}

function getUserInfo() {
    var html = java.ajax(baseUrl + "/?d=user");

    var nickMatch = html.match(/<div class="account_box">\s*<div>([^<]+)<\/div>/);
    var levelMatch = html.match(/<p>([^<]+会员)<\/p>/);
    var coinMatch = html.match(/<p>金币：(\d+)个<\/p>/);

    var nick = nickMatch ? nickMatch[1].trim() : "未知";
    var level = levelMatch ? levelMatch[1].trim() : "未知";
    var coins = coinMatch ? coinMatch[1].trim() : "0";

    java.longToast(`昵称：${nick}；会员等级：${level}；金币总数：${coins}`);
}

