function register() {
    const url = baseUrl.replace(/\/+$/, '').replace(/[^\w.:/-]/g, '');

        const randomUsername = generateRandomString(8); // 随机用户名
    const randomPassword = generateRandomString(10); // 随机密码

    const domains = ["qq.com", "gmail.com", "163.com", "outlook.com"]; // 邮箱池
    const randomDomain = domains[Math.floor(Math.random() * domains.length)]; // 随机选择邮箱域名：生成0到domains.length-1的随机索引

    const randomEmail = generateRealisticEmail(randomDomain); // 随机邮箱
    const randomNickname = generateRandomString(6); // 随机昵称

    const body = JSON.stringify({
        username: randomUsername, 
        password: randomPassword, 
        email: randomEmail,
        nickname: randomNickname
    });

    java.log("尝试注册: " + body);
    const response = java.post(
    	`${url}/api/user/register`,
    	 body, 
    {"Content-Type": "application/json", "x-requested-with": "XMLHttpRequest"});

    const result = JSON.parse(response.body());
    if (result.code === 200) {
        const token = result.data.token;
        const authHeader = JSON.stringify({Authorization: `Bearer ${token}`, Cookie: `authToken=${token}`});
        source.putLoginInfo(JSON.stringify({"用户名": randomUsername, "密码": randomPassword}));
        java.longToast("注册成功");
        return source.putLoginHeader(authHeader);
    }

    throw Error(result.msg || "注册失败");
}

function generateRandomString(length, includeNumbers = true) {
    const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    let result = '';
    for (let i = 0; i < length; i++) result += chars[Math.floor(Math.random() * chars.length)];
    return result;
}

function generateRealisticEmail(domain) {
    let username;
    switch (domain) {
        case "qq.com":
            username = Math.floor(100000000 + Math.random() * 900000000).toString();
            break;

        case "163.com":
            username = generateRandomString(6 + Math.floor(Math.random() * 4), true);
            if (Math.random() > 0.6) username = username.slice(0, 3) + '_' + username.slice(3);
            break;

        case "outlook.com":
            username = generateRandomString(6 + Math.floor(Math.random() * 4), true);
            if (Math.random() > 0.7) username = username.slice(0, 3) + '.' + username.slice(3);
            break;

        default:
            username = generateRandomString(7 + Math.floor(Math.random() * 5), true);
            break;
    }

    return username + "@" + domain;
}

function login() {
	    const url = baseUrl.replace(/\/+$/, '').replace(/[^\w.:/-]/g, '');
    const user = source.getLoginInfoMap();

    const response = java.post(
    	`${url}/api/user/login`, 
        JSON.stringify({username: user.get("用户名"), password: user.get("密码")}),
        {"Content-Type": "application/json", "x-requested-with": "XMLHttpRequest"}
    );

    const result = JSON.parse(response.body());
    if (result.code === 200 && result.msg === "Login successful") {
        const token = result.data.token;
        return source.putLoginHeader(JSON.stringify({Authorization: `Bearer ${token}`, Cookie: `authToken=${token}`}));
    }

    throw Error(result.msg || "登录失败");
}

